import json, os, pathlib

OUT_DIR = 'data/biblepedia/articles'
os.makedirs(OUT_DIR, exist_ok=True)

def load_article(slug):
    p = pathlib.Path(OUT_DIR) / f'{slug}.json'
    return json.loads(p.read_text()) if p.exists() else None

def save_article(slug, data):
    p = pathlib.Path(OUT_DIR) / f'{slug}.json'
    p.write_text(json.dumps(data, indent=2, ensure_ascii=False))

def merge_article(slug, data):
    if load_article(slug) is not None:
        return False
    save_article(slug, data)
    return True

ARTICLES = {
"naam": {"term":"Naam","category":"people","hitchcock_meaning":"fair; pleasant","source_ids":{"easton":"naam","smith":"naam","isbe":"naam"},"key_refs":["1 Chronicles 4:15"],"intro":"<p>Naam (meaning <em>pleasant; fair</em>) was one of the sons of Caleb, son of Jephunneh, listed in the genealogy of Judah (1 Chr. 4:15). Nothing further is recorded of him beyond this single genealogical reference. His name places him within the Calebite clan that settled in the Negev region of southern Judah following the conquest of Canaan.</p>"},
"naamah": {"term":"Naamah","category":"people","hitchcock_meaning":"beautiful; agreeable","source_ids":{"easton":"naamah","smith":"naamah"},"key_refs":["Genesis 4:22","1 Kings 14:21","1 Chronicles 4:28"],"intro":"<p>Naamah (meaning <em>beautiful; agreeable</em>) is the name of three women in the Old Testament. (1.) The daughter of Lamech and Zillah and sister of Tubal-cain — one of the few women named in the antediluvian genealogy (Gen. 4:22). (2.) An Ammonitess who was a wife of Solomon and mother of Rehoboam, his successor as king of Judah (1 Kgs. 14:21, 31; 2 Chr. 12:13). Her foreign origin illustrates the consequences of Solomon's many marriages to women from nations whose worship the law forbade. (3.) A town in the lowland of Judah (Josh. 15:41), the home of Zophar the Naamathite, one of Job's three friends (Job 2:11).</p>"},
"naaman": {"term":"Naaman","category":"people","hitchcock_meaning":"beautiful; agreeable","source_ids":{"easton":"naaman","smith":"naaman","isbe":"naaman"},"key_refs":["2 Kings 5:1","2 Kings 5:10","2 Kings 5:14","Luke 4:27"],"intro":"<p>Naaman (meaning <em>pleasantness</em>) was the commander of the army of Benhadad II of Syria, a great and valiant warrior who was afflicted with leprosy (2 Kgs. 5:1). A captive Israelite servant girl told his wife of Elisha the prophet in Samaria who could heal him. Naaman came with a letter from the king of Syria, horses, and chariots to Elisha's door, but was offended when Elisha simply sent a messenger instructing him to wash seven times in the Jordan. His servants persuaded him to obey, and he was healed. Naaman's subsequent confession — \"there is no God in all the earth but in Israel\" (2 Kgs. 5:15) — stands as a remarkable Gentile acknowledgment of the LORD. Jesus cited his healing in the synagogue at Nazareth as an example of divine grace extending beyond Israel (Luke 4:27).</p>"},
"naamathite": {"term":"Naamathite","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"naamathite","smith":"naamathite","isbe":"naamathite"},"key_refs":["Job 2:11","Job 11:1","Job 20:1","Job 42:9"],"intro":"<p>Naamathite is the gentile designation of Zophar, one of Job's three friends (Job 2:11; 11:1; 20:1; 42:9). It indicates that Zophar came from Naamah, a place whose location remains uncertain — possibly in Arabia or Edom. Along with Eliphaz and Bildad, Zophar came to comfort Job in his suffering. His speeches represent the most dogmatic of the three friends' positions: he insists that Job's suffering must be the direct consequence of hidden sin and that God is actually punishing him less than he deserves (Job 11:6). At the end of the book God rebukes all three friends for not speaking rightly about him, requiring them to offer sacrifices and have Job pray for them (Job 42:7–9).</p>"},
"naarah": {"term":"Naarah","category":"people","hitchcock_meaning":"young person","source_ids":{"easton":"naarah","smith":"naarah"},"key_refs":["1 Chronicles 4:5","1 Chronicles 4:6"],"intro":"<p>Naarah (meaning <em>young woman; girl</em>) was one of the two wives of Ashhur the founder of Tekoa, listed in the genealogy of Judah (1 Chr. 4:5–6). She bore him four sons: Ahuzzam, Hepher, Temeni, and Haahashtari. Beyond this genealogical notice she is otherwise unknown. Her name also appears as a border town in Ephraim (Josh. 16:7), likely a different place derived from the same root.</p>"},
"naarai": {"term":"Naarai","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"naarai","smith":"naarai","isbe":"naarai"},"key_refs":["1 Chronicles 11:37","2 Samuel 23:35"],"intro":"<p>Naarai (or Paarai in 2 Sam. 23:35, possibly a textual variant) was the son of Ezbai and one of David's elite corps of thirty mighty warriors (1 Chr. 11:37). He is listed among the renowned fighters who distinguished themselves in David's service during the period of his kingdom's establishment. Beyond his inclusion in this roster of heroes nothing further is recorded of him.</p>"},
"naaran": {"term":"Naaran","category":"places","hitchcock_meaning":None,"source_ids":{"easton":"naaran","smith":"naaran"},"key_refs":["1 Chronicles 7:28"],"intro":"<p>Naaran (also Naarath, Josh. 16:7) was a town in the territory of Ephraim, mentioned in 1 Chronicles 7:28 as part of the Ephraimite settlements. It is identified as lying east of Bethel in the Jordan valley region. The town is otherwise historically obscure, known only from these two brief geographical references.</p>"},
"naarath": {"term":"Naarath","category":"places","hitchcock_meaning":None,"source_ids":{"easton":"naarath","smith":"naarath"},"key_refs":["Joshua 16:7"],"intro":"<p>Naarath was a town on the southern border of Ephraim, mentioned in Joshua 16:7 as a boundary marker in the territorial allotment for that tribe. It is likely the same place as Naaran in 1 Chronicles 7:28, lying in the Jordan valley region east of Bethel. Its exact site has not been definitively identified.</p>"},
"nabal": {"term":"Nabal","category":"people","hitchcock_meaning":"fool; senseless","source_ids":{"easton":"nabal","smith":"nabal","isbe":"nabal"},"key_refs":["1 Samuel 25:3","1 Samuel 25:10","1 Samuel 25:37","1 Samuel 25:38"],"intro":"<p>Nabal (meaning <em>fool; senseless</em>) was a wealthy Calebite of Maon who owned 3,000 sheep and 1,000 goats and was \"churlish and evil in his doings\" (1 Sam. 25:2–3). When David's men requested provisions as recompense for protecting Nabal's flocks in the wilderness, Nabal contemptuously refused and insulted David. David set out to destroy Nabal's household, but Nabal's wife Abigail interceded with a generous gift and wise words that stayed David's hand. When Abigail later told Nabal what had happened, \"his heart died within him and he became as a stone\" — he was struck with a fatal illness and died about ten days later (1 Sam. 25:37–38). David then took Abigail as his wife. The episode illustrates the principle that vengeance belongs to God and that the wise, not the powerful, avert disaster.</p>"},
"naboth": {"term":"Naboth","category":"people","hitchcock_meaning":"words; prophecies","source_ids":{"easton":"naboth","smith":"naboth","isbe":"naboth"},"key_refs":["1 Kings 21:1","1 Kings 21:3","1 Kings 21:13","2 Kings 9:26"],"intro":"<p>Naboth the Jezreelite was the owner of a vineyard adjoining the royal palace in Jezreel, which Ahab coveted for a vegetable garden (1 Kgs. 21:1–2). Naboth refused to sell or exchange it, citing the Mosaic law that forbade the permanent alienation of ancestral land (Lev. 25:23): \"The LORD forbid it me, that I should give the inheritance of my fathers unto thee\" (1 Kgs. 21:3). Jezebel arranged his judicial murder by suborning false witnesses who accused him of blaspheming God and king, and had him stoned. Elijah confronted Ahab in Naboth's vineyard and pronounced doom on Ahab's dynasty (1 Kgs. 21:17–24). The fulfillment of this prophecy — Jehu's execution of Joram and the casting of his body into Naboth's field (2 Kgs. 9:25–26) — became a landmark example of divine justice vindicated.</p>"},
"nachon": {"term":"Nachon","category":"places","hitchcock_meaning":None,"source_ids":{"easton":"nachon"},"key_refs":["2 Samuel 6:6"],"intro":"<p>Nachon (also spelled Nacon) was the owner of the threshing floor near which Uzzah was struck dead when he reached out his hand to steady the ark of the covenant as it was being transported to Jerusalem on a cart (2 Sam. 6:6). The site was afterward called Perez-uzzah (\"the breaking out upon Uzzah\") in memory of the event. The incident caused David to leave the ark for three months in the house of Obed-edom before resuming its transport to Jerusalem, this time carried properly by Levites on poles (1 Chr. 15:2, 13).</p>"},
"nadab": {"term":"Nadab","category":"people","hitchcock_meaning":"free and voluntary gift; prince","source_ids":{"easton":"nadab","smith":"nadab","isbe":"nadab"},"key_refs":["Exodus 6:23","Leviticus 10:1","Leviticus 10:2","1 Kings 15:25"],"intro":"<p>Nadab (meaning <em>willing; noble</em>) is the name of several men. (1.) The eldest son of Aaron and Elisheba (Ex. 6:23), consecrated with his brothers and father as a priest (Ex. 28:1). He and his brother Abihu \"offered strange fire before the LORD, which he commanded them not\" and were consumed by fire from the LORD's presence (Lev. 10:1–2). They died childless, and the high-priestly line descended through their brothers Eleazar and Ithamar. (2.) The son of Jeroboam I and second king of Israel (c. 910–909 B.C.), who \"did evil in the sight of the LORD\" following his father's idolatry (1 Kgs. 15:25–26). He was assassinated by Baasha while besieging Gibbethon, fulfilling Ahijah's prophecy against Jeroboam's house (1 Kgs. 15:27–29).</p>"},
"nagge": {"term":"Nagge","category":"people","hitchcock_meaning":"clearness; brightness; light","source_ids":{"easton":"nagge","smith":"nagge"},"key_refs":["Luke 3:25"],"intro":"<p>Nagge (also Naggai) appears in Luke's genealogy of Jesus Christ as an ancestor through the line of David (Luke 3:25). He is listed between Maath and Esli in the descent from David through Nathan rather than Solomon. Beyond this genealogical reference nothing is known of him; his name is the Greek form of the Hebrew <em>Nogah</em>, meaning \"brightness\" or \"clearness.\"</p>"},
"nahaliel": {"term":"Nahaliel","category":"places","hitchcock_meaning":"inheritance; valley of God","source_ids":{"easton":"nahaliel","smith":"nahaliel","isbe":"nahaliel"},"key_refs":["Numbers 21:19"],"intro":"<p>Nahaliel (meaning <em>valley of God; inheritance of God</em>) was a stopping place of the Israelites during their wilderness journey, listed in Numbers 21:19 between Mattanah and Bamoth in the region east of the Dead Sea. It was probably a wadi or stream-valley in the territory of Moab, possibly identified with the Wadi Zerqa Ma'in that runs into the Dead Sea from the east. The name suggests a well-watered ravine understood as God's provision.</p>"},
"nahallal": {"term":"Nahallal","category":"places","hitchcock_meaning":None,"source_ids":{"easton":"nahallal"},"key_refs":["Joshua 19:15","Joshua 21:35","Judges 1:30"],"intro":"<p>Nahallal (also Nahalal or Nahalol) was a town in the territory of Zebulun assigned as one of the Levitical cities for the Merarite clan (Josh. 19:15; 21:35). The Canaanite inhabitants were not expelled but were put under tribute (Judg. 1:30). Its exact location in the Jezreel valley has been identified with Tell en-Nahl or possibly Malul, but the identification is not certain.</p>"},
"naharai": {"term":"Naharai","category":"people","hitchcock_meaning":"my nostrils; hot; anger","source_ids":{"easton":"naharai","smith":"naharai","isbe":"naharai"},"key_refs":["2 Samuel 23:37","1 Chronicles 11:39"],"intro":"<p>Naharai the Beerothite was the armor-bearer of Joab, commander of David's army, and one of the thirty elite warriors known as David's mighty men (2 Sam. 23:37; 1 Chr. 11:39). The role of armor-bearer was one of trusted personal service and combat proximity to the commander. Nothing further is recorded of Naharai beyond his inclusion in this honored list.</p>"},
"nahash": {"term":"Nahash","category":"people","hitchcock_meaning":"snake; serpent","source_ids":{"easton":"nahash","smith":"nahash","isbe":"nahash"},"key_refs":["1 Samuel 11:1","1 Samuel 11:2","2 Samuel 10:2","2 Samuel 17:25"],"intro":"<p>Nahash (meaning <em>serpent</em>) is the name of two Ammonite kings. (1.) The king of Ammon who besieged Jabesh-gilead and threatened to gouge out the right eye of every man in the city — an act of cruelty that provoked Saul's first great military action and contributed to his popular acceptance as king (1 Sam. 11:1–11). His defeat at Jabesh-gilead was one of Saul's defining early victories. (2.) A later king of Ammon, father of Hanun, who had shown kindness to David. When Hanun humiliated David's emissaries sent to mourn his father's death, it triggered the Ammonite-Syrian war (2 Sam. 10:1–5).</p>"},
"nahath": {"term":"Nahath","category":"people","hitchcock_meaning":"rest; a leader","source_ids":{"easton":"nahath","smith":"nahath","isbe":"nahath"},"key_refs":["Genesis 36:13","1 Chronicles 6:26","2 Chronicles 31:13"],"intro":"<p>Nahath (meaning <em>rest; descent</em>) is the name of three men. (1.) A son of Reuel and grandson of Esau, and a chief (alluf) of Edom (Gen. 36:13, 17; 1 Chr. 1:37). (2.) A Levite in the line of Kohath, ancestor of Samuel the prophet (1 Chr. 6:26). (3.) A Levite appointed by Hezekiah as one of the overseers of the temple contributions and firstfruits during his religious reform (2 Chr. 31:13).</p>"},
"nahbi": {"term":"Nahbi","category":"people","hitchcock_meaning":"very secret","source_ids":{"easton":"nahbi","smith":"nahbi","isbe":"nahbi"},"key_refs":["Numbers 13:14"],"intro":"<p>Nahbi (meaning <em>hidden; very secret</em>) was the son of Vophsi, from the tribe of Naphtali, and one of the twelve spies sent by Moses to explore Canaan (Num. 13:14). He is otherwise unattested, and his name does not recur in the subsequent narrative. Like ten of the twelve spies, he is presumed to have been among those who brought back the discouraging report that led to Israel's forty years of wilderness wandering.</p>"},
"nahor": {"term":"Nahor","category":"people","hitchcock_meaning":"hoarse; dry; hot","source_ids":{"easton":"nahor","smith":"nahor","isbe":"nahor"},"key_refs":["Genesis 11:22","Genesis 11:26","Genesis 22:20","Genesis 24:10"],"intro":"<p>Nahor (meaning <em>snorer; hoarse</em>) is the name of two ancestors of Abraham. (1.) The grandfather of Abraham, son of Serug, who lived 148 years (Gen. 11:22–25). (2.) The brother of Abraham, son of Terah, who remained at Haran when Abraham departed for Canaan (Gen. 11:26–29). This Nahor married his niece Milcah and had eight sons with her and four sons with his concubine Reumah (Gen. 22:20–24). His grandson Bethuel was the father of Rebekah and Laban, making him the ancestor of both Isaac's wife and Jacob's wives. The city of Haran is sometimes called \"the city of Nahor\" (Gen. 24:10).</p>"},
"nahshon": {"term":"Nahshon","category":"people","hitchcock_meaning":"same as Naashon","source_ids":{"easton":"nahshon","isbe":"nahshon"},"key_refs":["Exodus 6:23","Numbers 1:7","Numbers 7:12","Matthew 1:4"],"intro":"<p>Nahshon (also Naasson) was the son of Amminadab and prince of the tribe of Judah during the wilderness period (Ex. 6:23; Num. 1:7). He was the first to bring his offering when the tabernacle was dedicated (Num. 7:12–17). As the brother-in-law of Aaron and the ancestor of Boaz, David, and ultimately Jesus Christ, Nahshon occupies a significant position in the messianic genealogy (Ruth 4:20–22; Matt. 1:4; Luke 3:32). Jewish tradition credits him with extraordinary faith in leading Israel into the Red Sea before the waters parted.</p>"},
"nahum": {"term":"Nahum","category":"people","hitchcock_meaning":"comforter; penitent","source_ids":{"easton":"nahum","smith":"nahum","isbe":"nahum"},"key_refs":["Nahum 1:1"],"intro":"<p>Nahum (meaning <em>consolation; comforter</em>) was a Hebrew prophet designated as an Elkoshite — a resident of Elkosh, a place whose location is disputed but possibly in Galilee or Judah (Nah. 1:1). Nothing is known of him beyond what is revealed in his prophecy. He prophesied the fall of Nineveh, the capital of the Assyrian empire, which he describes in vivid detail. The prophecy is generally dated between 663 B.C. (the fall of Thebes, which Nahum mentions as a past event in 3:8) and 612 B.C. (the actual fall of Nineveh). His message provides the counter-balance to Jonah: where Jonah recorded Nineveh's temporary repentance and sparing, Nahum announces its ultimate and permanent destruction.</p>"},
"nahum-book-of": {"term":"Nahum, Book of","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"nahum-book-of"},"key_refs":["Nahum 1:1","Nahum 1:7","Nahum 3:1","Nahum 3:7"],"intro":"<p>The Book of Nahum consists of three chapters prophesying the imminent destruction of Nineveh, the capital of the Assyrian empire, which fell to the Babylonians and Medes in 612 B.C. The book is dated between 663 B.C. (the fall of Thebes mentioned in 3:8 as past) and 612 B.C. Its theology balances divine justice — \"The LORD is a jealous God and avenging\" (1:2) — with divine mercy toward his own: \"The LORD is good, a stronghold in the day of trouble; he knows those who take refuge in him\" (1:7). The vivid battle poetry of chapters 2–3 describes Nineveh's siege and fall in remarkable detail, depicting charging cavalry, flashing swords, and heaps of slain that would have been recognized by contemporary readers as depicting the Assyrian military machine turned against its own capital. The book balances Jonah's message of repentance and mercy toward Nineveh with the certainty of judgment when repentance does not endure.</p>"},
"nail": {"term":"Nail","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"nail","smith":"nail","isbe":"nail"},"key_refs":["Judges 4:21","Ezra 9:8","Isaiah 22:23","Colossians 2:14"],"intro":"<p>Nail in Scripture refers to several distinct objects. (1.) The tent-peg (Hebrew <em>yathed</em>) driven into the ground to anchor tent ropes — most notably the tent-peg Jael used to kill Sisera (Judg. 4:21). (2.) Metal fastening nails (Hebrew <em>masmer</em>) used in construction, including those David prepared for the temple (1 Chr. 22:3). (3.) The human fingernail or toenail (Hebrew <em>tsipporen</em>), mentioned in Deuteronomy 21:12. The figurative uses are significant: the messianic servant is compared to \"a nail fastened in a sure place\" (Isa. 22:23), while Paul declares that the legal record of demands against us was nailed to Christ's cross (Col. 2:14) — an image of cancellation of debt by the crucifixion.</p>"},
"nain": {"term":"Nain","category":"places","hitchcock_meaning":"beauty; pleasantness","source_ids":{"easton":"nain","smith":"nain","isbe":"nain"},"key_refs":["Luke 7:11","Luke 7:14","Luke 7:15"],"intro":"<p>Nain (meaning <em>lovely; pleasant</em>) was a village in Galilee at whose gate Jesus raised the only son of a widow from the dead (Luke 7:11–17). The miracle, performed without any request or expressed faith, demonstrated Christ's sovereign compassion for the bereaved. Nain is identified with the modern village of Nein on the northwestern slope of the hill of Moreh (\"Little Hermon\"), about six miles southeast of Nazareth. The village would have been visible from Nazareth. The raising of the widow's son echoed Elijah's similar miracle at Zarephath (1 Kgs. 17:17–24) and identified Jesus as a prophet greater than Elijah.</p>"},
"naioth": {"term":"Naioth","category":"places","hitchcock_meaning":"beauties; habitations","source_ids":{"easton":"naioth","smith":"naioth","isbe":"naioth"},"key_refs":["1 Samuel 19:18","1 Samuel 19:20","1 Samuel 19:23","1 Samuel 20:1"],"intro":"<p>Naioth was a place in Ramah where Samuel presided over a community of prophets, and to which David fled when he escaped from Saul (1 Sam. 19:18). When Saul sent successive companies of messengers to seize David, the Spirit of God came upon them and they prophesied instead. Saul himself then went to Naioth, and he too was seized by the Spirit, stripped off his clothes, and lay prophesying before Samuel all day and night — giving rise to the proverb \"Is Saul also among the prophets?\" (1 Sam. 19:20–24). The name probably refers to the dwelling-place or school associated with Samuel's prophetic community.</p>"},
"naked": {"term":"Naked","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"naked","isbe":"naked"},"key_refs":["Genesis 2:25","Genesis 3:7","Job 1:21","Isaiah 20:3"],"intro":"<p>Naked and nakedness in Scripture carry several distinct meanings. (1.) The original state of innocence in the garden, where Adam and Eve \"were both naked and not ashamed\" (Gen. 2:25) — a condition of perfect transparency before God and each other. (2.) The shame that followed sin, when they recognized their nakedness and covered themselves (Gen. 3:7), establishing modesty and clothing as consequences of the fall. (3.) Prophetic sign-act: Isaiah walked naked and barefoot for three years as a sign of Assyrian captivity (Isa. 20:3). (4.) Theological vulnerability: Job's declaration \"Naked I came from my mother's womb, and naked shall I return\" (Job 1:21) expresses absolute dependence on God.</p>"},
"naomi": {"term":"Naomi","category":"people","hitchcock_meaning":"beautiful; agreeable","source_ids":{"easton":"naomi","smith":"naomi","isbe":"naomi"},"key_refs":["Ruth 1:2","Ruth 1:20","Ruth 2:1","Ruth 4:16"],"intro":"<p>Naomi (meaning <em>my delight; pleasant</em>), wife of Elimelech of Bethlehem-Judah, accompanied her husband and two sons to Moab during a famine. In Moab her husband and both sons died, leaving her with her two Moabite daughters-in-law, Orpah and Ruth. Naomi resolved to return to Bethlehem and urged her daughters-in-law to return to their own families. Orpah departed, but Ruth clung to Naomi with the famous declaration of loyal love: \"Where you go I will go\" (Ruth 1:16). On returning to Bethlehem Naomi requested to be called Mara (\"bitter\"), saying \"the Almighty has dealt very bitterly with me\" (Ruth 1:20). The book of Ruth traces how God's providence through Ruth's marriage to Boaz restored Naomi to fullness — she became nurse to Ruth and Boaz's son Obed, grandfather of David (Ruth 4:16–17).</p>"},
"naphish": {"term":"Naphish","category":"people","hitchcock_meaning":"the soul; he that rests","source_ids":{"easton":"naphish","smith":"naphish","isbe":"naphish"},"key_refs":["Genesis 25:15","1 Chronicles 1:31","1 Chronicles 5:19"],"intro":"<p>Naphish (meaning <em>refreshed; he that rests</em>) was the eleventh son of Ishmael and grandson of Abraham through Hagar (Gen. 25:15; 1 Chr. 1:31). He is the ancestor of the Naphishites, an Arabian tribe that was defeated by the Reubenites, Gadites, and the half-tribe of Manasseh east of the Jordan (1 Chr. 5:19). The tribe submitted to Israel and their flocks and goods were taken as spoil.</p>"},
"naphtali": {"term":"Naphtali","category":"people","hitchcock_meaning":"that struggles or fights","source_ids":{"easton":"naphtali","smith":"naphtali","isbe":"naphtali"},"key_refs":["Genesis 30:8","Genesis 46:24","Genesis 49:21","Matthew 4:15"],"intro":"<p>Naphtali (meaning <em>my wrestling</em>), sixth son of Jacob and second son of Bilhah, Rachel's handmaid, was born after Rachel declared, \"I have wrestled greatly with my sister and have prevailed\" (Gen. 30:8). He had four sons when the family descended to Egypt (Gen. 46:24). Jacob's blessing describes him as \"a doe let loose\" who \"gives beautiful words\" (Gen. 49:21). The tribe of Naphtali received territory in the far north of Canaan around the Sea of Galilee and west of the upper Jordan. The region \"Naphtali\" later became synonymous with Galilee of the nations — the territory where Jesus began his Galilean ministry, fulfilling Isaiah's prophecy (Isa. 9:1–2; Matt. 4:15–16).</p>"},
"naphtali-mount": {"term":"Naphtali, Mount","category":"places","hitchcock_meaning":None,"source_ids":{"easton":"naphtali-mount","smith":"naphtali-mount","isbe":"naphtali-mount"},"key_refs":["Joshua 20:7"],"intro":"<p>Mount Naphtali designates the mountainous region within the tribal territory of Naphtali in the far north of Canaan (Josh. 20:7). Kedesh in the hill country of Naphtali was designated as one of the six cities of refuge (Josh. 20:7; 21:32). The terrain of Naphtali is rugged highland lying west of the upper Jordan valley and north of the Sea of Galilee, rising to the heights of Upper Galilee.</p>"},
"naphtali-tribe-of": {"term":"Naphtali, Tribe of","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"naphtali-tribe-of"},"key_refs":["Numbers 1:42","Numbers 2:29","Judges 4:6","Isaiah 9:1"],"intro":"<p>The tribe of Naphtali, descended from Jacob's sixth son, received territory in the northernmost region of Canaan bordering Asher, Zebulun, and Issachar to the south and west, and Syria to the north (Josh. 19:32–39). In the census at Sinai they numbered 53,400 fighting men (Num. 1:42–43). Barak, the general who led Israel against Sisera under Deborah's direction, was from Naphtali (Judg. 4:6), as was Naphtali's primary contribution to that campaign (Judg. 5:18). The territory was the first to be carried into captivity by Tiglath-pileser of Assyria (2 Kgs. 15:29), fulfilling the \"way of the sea\" geography of Isaiah 9:1 that Jesus' Galilean ministry would later illuminate (Matt. 4:15).</p>"},
"naphtuhim": {"term":"Naphtuhim","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"naphtuhim","smith":"naphtuhim","isbe":"naphtuhim"},"key_refs":["Genesis 10:13","1 Chronicles 1:11"],"intro":"<p>Naphtuhim was a son of Mizraim (Egypt) in the table of nations, representing one of the peoples descended from Ham through the Egyptian branch (Gen. 10:13; 1 Chr. 1:11). The Naphtuhim are generally identified with a North African or Delta people of Egypt, possibly the inhabitants of the central Delta region, though the precise identification remains uncertain. Like the other sons of Mizraim they represent tribal or ethnic groups of the ancient Near Eastern world.</p>"},
"napkin": {"term":"Napkin","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"napkin","isbe":"napkin"},"key_refs":["Luke 19:20","John 11:44","John 20:7"],"intro":"<p>Napkin (Greek <em>soudarion</em>, from Latin <em>sudarium</em>, a sweat-cloth) refers to a cloth wrapped around the head of a dead person for burial. Lazarus came out of his tomb \"with his face bound about with a napkin\" (John 11:44). The napkin that had been on Jesus' head was found rolled up separately from the burial cloths in the empty tomb (John 20:7) — a detail noted by John as significant. The same word appears in the parable of the talents for the cloth in which the unprofitable servant hid his one talent (Luke 19:20).</p>"},
"narcissus": {"term":"Narcissus","category":"people","hitchcock_meaning":"astonishment; stupidity","source_ids":{"easton":"narcissus","smith":"narcissus","isbe":"narcissus"},"key_refs":["Romans 16:11"],"intro":"<p>Narcissus is mentioned by Paul in Romans 16:11 in the greeting \"Greet those in the Lord who belong to the family of Narcissus.\" He appears to have been a notable Roman householder whose household included Christian slaves or freedmen. Some scholars have identified him with the influential freedman Tiberius Claudius Narcissus, secretary to the Emperor Claudius, whose household slaves would have passed to the imperial household after his death. Paul's phrasing suggests Narcissus himself may not have been a believer, but that members of his household were.</p>"},
"nathan": {"term":"Nathan","category":"people","hitchcock_meaning":"given; giving; rewarded","source_ids":{"easton":"nathan","smith":"nathan","isbe":"nathan"},"key_refs":["2 Samuel 7:2","2 Samuel 12:1","2 Samuel 12:7","1 Kings 1:45"],"intro":"<p>Nathan (meaning <em>gift; given</em>) was the court prophet during the reigns of David and Solomon. He delivered God's response to David's desire to build the temple — the Davidic covenant in which God promised David an eternal dynasty (2 Sam. 7:4–17). His most significant act was his confrontation of David after the sin with Bathsheba: he told the parable of the poor man's lamb, leading David to condemn himself, then declared \"You are the man\" (2 Sam. 12:7) and announced the consequences of David's sin. Nathan also played a decisive role in the succession crisis, supporting Solomon against Adonijah's claim to the throne (1 Kgs. 1:11–45). He authored chronicles of the reigns of David and Solomon (2 Chr. 9:29). A son named Nathan also appears in David's genealogy as an ancestor of Jesus through Mary's line (Luke 3:31).</p>"},
"nathanael": {"term":"Nathanael","category":"people","hitchcock_meaning":"the gift of God","source_ids":{"easton":"nathanael","smith":"nathanael","isbe":"nathanael"},"key_refs":["John 1:45","John 1:46","John 1:47","John 21:2"],"intro":"<p>Nathanael (meaning <em>God has given</em>), a disciple of Jesus \"of Cana in Galilee\" (John 21:2), was brought to Jesus by Philip with the invitation, \"Come and see\" (John 1:45–46). His initial skepticism — \"Can any good thing come out of Nazareth?\" — was immediately overcome when Jesus demonstrated supernatural knowledge: \"Behold, an Israelite indeed, in whom there is no deceit\" (John 1:47). Nathanael's astonished confession — \"Rabbi, you are the Son of God! You are the King of Israel!\" (John 1:49) — is one of the earliest Christological declarations in John's Gospel. He is widely identified with Bartholomew in the Synoptics, as John never mentions Bartholomew and the Synoptics never mention Nathanael.</p>"},
"nativity-of-christ": {"term":"Nativity of Christ","category":"events","hitchcock_meaning":None,"source_ids":{"easton":"nativity-of-christ"},"key_refs":["Isaiah 7:14","Micah 5:2","Matthew 1:18","Luke 2:7"],"intro":"<p>The nativity of Christ — the birth of Jesus of Nazareth — fulfilled multiple prophetic predictions: that the Messiah would be born of a virgin (Isa. 7:14; Matt. 1:22–23), that his birthplace would be Bethlehem of Judah (Mic. 5:2; Matt. 2:6), and that the flight to Egypt and the slaughter of Bethlehem's children would occur (Hos. 11:1; Jer. 31:15; Matt. 2:15–18). Luke records the birth in a manger because there was no room in the inn (Luke 2:7), the announcement to shepherds by angels, and the visit of the magi (recorded in Matthew 2). The date of the nativity is uncertain; early church fathers proposed dates in spring or autumn, and December 25 was established as the Western liturgical observance by the 4th century. The incarnation — God taking on human nature in Jesus — is theologically central to both soteriology (Christ as the second Adam) and Christology (the hypostatic union of divine and human natures).</p>"},
"naughty-figs": {"term":"Naughty Figs","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"naughty-figs"},"key_refs":["Jeremiah 24:2","Jeremiah 24:8"],"intro":"<p>Naughty figs (Hebrew <em>te'enim ra'im</em>, \"bad figs\") appear in Jeremiah's vision of two baskets of figs set before the temple (Jer. 24:1–10). The vision came after the first Babylonian deportation (597 B.C.). The good figs represented the exiles carried to Babylon, whom God promised to restore and make his own people. The bad figs — described as \"so bad they cannot be eaten\" — represented Zedekiah and the remnant left in Judah together with those who went to Egypt, whom God would make a reproach and a curse among all nations. The vision inverted popular expectation: those remaining in the land were not the fortunate ones but the abandoned ones.</p>"},
"nazarene": {"term":"Nazarene","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"nazarene","smith":"nazarene","isbe":"nazarene"},"key_refs":["Matthew 2:23","Mark 1:24","Mark 10:47","Acts 2:22"],"intro":"<p>Nazarene (Greek <em>Nazaraios</em>) was the epithet applied to Jesus, identifying him as a man from Nazareth. Matthew 2:23 cites the prophetic fulfillment \"He shall be called a Nazarene\" — a citation whose source in the Old Testament is much debated, with scholars proposing connections to the Hebrew <em>netser</em> (\"branch,\" Isa. 11:1) or to the concept of the Nazirite. Enemies used it disparagingly: the blind Bartimaeus called out \"Jesus, son of David\" but others in the crowd used \"Jesus of Nazareth\" (Mark 10:47). At the crucifixion Pilate had it inscribed above the cross (John 19:19). Acts 2:22 uses \"Jesus of Nazareth\" in the first apostolic sermon. Early Jewish-Christian groups were sometimes called \"Nazarenes\" (<em>Notzrim</em>), a term still used for Christians in Hebrew and Arabic.</p>"},
"nazareth": {"term":"Nazareth","category":"places","hitchcock_meaning":"separated; crowned; sanctified","source_ids":{"easton":"nazareth","smith":"nazareth","isbe":"nazareth"},"key_refs":["Luke 2:39","Luke 4:16","Matthew 13:54","Luke 4:29"],"intro":"<p>Nazareth was a town in lower Galilee where Jesus was raised, the home of Mary and Joseph (Luke 1:26; 2:39, 51). It lay in a sheltered hollow among the hills of Galilee, about 15 miles from the Sea of Galilee and 6 miles west of Mount Tabor. Its Jewish population was of sufficient size to support a synagogue where Jesus read from Isaiah 61 and applied it to himself (Luke 4:16–21). The town's obscurity is captured in Nathanael's question: \"Can any good thing come out of Nazareth?\" (John 1:46). When Jesus returned and preached there, his own townspeople rejected him and attempted to cast him off a cliff (Luke 4:28–30). The identification of \"Jesus of Nazareth\" served as both a geographical designation and, in Roman-era Jerusalem, a mark of provincial origin.</p>"},
"nazarite": {"term":"Nazirite","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"nazarite","smith":"nazarite","isbe":"nazarite"},"key_refs":["Numbers 6:2","Numbers 6:3","Numbers 6:5","Judges 13:5"],"intro":"<p>A Nazirite (Hebrew <em>nazir</em>, meaning \"consecrated; set apart\") was an Israelite who took a special vow of dedication to God involving three main abstentions: from wine and all grape products, from cutting the hair, and from contact with a dead body (Num. 6:2–8). The vow could be for a set period or, in exceptional cases, for life — Samson (Judg. 13:5), Samuel (1 Sam. 1:11), and John the Baptist (Luke 1:15) being the notable lifelong Nazirites. The Nazirite vow expressed intensified devotion to the LORD, and its regulations appear in Numbers 6 along with the purification and concluding sacrifices at the vow's termination. Paul apparently participated in a Nazirite-related purification vow to demonstrate his respect for Jewish practice (Acts 18:18; 21:23–24).</p>"},
"neah": {"term":"Neah","category":"places","hitchcock_meaning":None,"source_ids":{"easton":"neah","smith":"neah","isbe":"neah"},"key_refs":["Joshua 19:13"],"intro":"<p>Neah was a town on the border of Zebulun mentioned in Joshua 19:13 as one of the boundary markers of that tribe's allotment. Its precise location has not been definitively identified, though some scholars place it in the Jezreel valley region. It appears only in this single territorial reference.</p>"},
"neapolis": {"term":"Neapolis","category":"places","hitchcock_meaning":"the new city","source_ids":{"easton":"neapolis","smith":"neapolis","isbe":"neapolis"},"key_refs":["Acts 16:11","Acts 20:6"],"intro":"<p>Neapolis (meaning <em>new city</em>) was the seaport of Philippi in Thrace (Macedonia), the first European town where Paul set foot during his second missionary journey (Acts 16:11). It lay on the Via Egnatia, the great Roman road linking Asia Minor with Rome, about 10 miles southeast of Philippi. Paul sailed from Troas to Neapolis in response to the Macedonian vision (Acts 16:9–11), a crossing that brought the gospel to Europe for the first time. He passed through it again at the end of the third missionary journey (Acts 20:6). The site is identified with modern Kavala in northeastern Greece.</p>"},
"nebaioth": {"term":"Nebaioth","category":"people","hitchcock_meaning":"words; prophecies; buds","source_ids":{"easton":"nebaioth","isbe":"nebaioth"},"key_refs":["Genesis 25:13","Genesis 28:9","Isaiah 60:7"],"intro":"<p>Nebaioth (also Nebajoth) was the firstborn son of Ishmael, son of Abraham and Hagar, and the ancestor of an Arabian tribe (Gen. 25:13; 1 Chr. 1:29). His sister Mahalath (or Basemath) was taken as a wife by Esau (Gen. 28:9; 36:3). The Nebaioth appear in Isaiah 60:7 in the eschatological vision of the nations bringing their wealth to Jerusalem: \"all the flocks of Kedar shall be gathered to you, the rams of Nebaioth shall minister to you.\" Ancient sources identify the Nebaioth with the Nabataeans, the powerful Arab kingdom whose capital was Petra, though the identification is debated.</p>"},
"neballat": {"term":"Neballat","category":"places","hitchcock_meaning":"prophecy; budding","source_ids":{"easton":"neballat","smith":"neballat","isbe":"neballat"},"key_refs":["Nehemiah 11:34"],"intro":"<p>Neballat was a town in Benjamin reoccupied by Benjaminite settlers after the return from the Babylonian exile (Neh. 11:34). It is mentioned in a list of post-exilic settlements alongside Hadid and Ono. The site is generally identified with modern Beit Nabala, north of Lydda in the coastal plain. Beyond this single reference it is historically unattested.</p>"},
"nebat": {"term":"Nebat","category":"people","hitchcock_meaning":"that beholds","source_ids":{"easton":"nebat","smith":"nebat","isbe":"nebat"},"key_refs":["1 Kings 11:26","1 Kings 12:2","1 Kings 15:1"],"intro":"<p>Nebat was the father of Jeroboam I, the first king of the northern kingdom of Israel. He is identified as \"an Ephrathite of Zereda\" (1 Kgs. 11:26), though little else is recorded of him personally. His name appears almost exclusively in the formulaic phrase \"Jeroboam the son of Nebat\" (appearing some 20 times in Kings and Chronicles), used in evaluative summaries of subsequent kings who \"walked in the sins of Jeroboam the son of Nebat\" — primarily the idolatrous calf worship at Bethel and Dan.</p>"},
"nebo": {"term":"Nebo","category":"places","hitchcock_meaning":"that speaks or prophesies","source_ids":{"easton":"nebo","smith":"nebo","isbe":"nebo"},"key_refs":["Numbers 32:38","Deuteronomy 34:1","Deuteronomy 32:49","Isaiah 46:1"],"intro":"<p>Nebo is the name of several places and one Babylonian deity. (1.) A mountain in Moab in the Abarim range, from whose summit Moses viewed the Promised Land before his death (Deut. 34:1; 32:49). It overlooks the northern end of the Dead Sea and the Jordan valley, and is identified with Jebel en-Neba. (2.) A town in the territory of Reuben east of the Jordan, mentioned in Numbers 32:38 and 1 Chronicles 5:8. (3.) A town in Judah whose people returned from exile (Ezra 2:29; Neh. 7:33). (4.) Nebo was also the name of the chief Babylonian deity of writing and wisdom, son of Bel-Marduk, mentioned in Isaiah 46:1 as falling prostrate before the advancing Medes — a taunt against the impotence of Babylon's gods.</p>"},
"nebuchadnezzar": {"term":"Nebuchadnezzar","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"nebuchadnezzar","isbe":"nebuchadnezzar"},"key_refs":["Daniel 1:1","2 Kings 24:1","Daniel 4:30","Jeremiah 27:6"],"intro":"<p>Nebuchadnezzar II (Babylonian <em>Nabu-kudurri-usur</em>, meaning \"Nebo, protect the crown\"), son of Nabopolassar, was the greatest king of the Neo-Babylonian Empire (reigned c. 605–562 B.C.) and the central foreign power in the books of Daniel, Jeremiah, and Kings. He defeated Pharaoh Necho at Carchemish (605 B.C.), subjugated Judah, and carried the first deportation to Babylon (Dan. 1:1–2). After Jehoiakim's rebellion he took the second deportation in 597 B.C. including Jehoiachin, and after Zedekiah's revolt he besieged Jerusalem for 18 months, destroyed Solomon's temple in 586 B.C., and carried the bulk of the remaining population into exile. God called him \"my servant\" as an instrument of judgment (Jer. 27:6). His pride was humbled in the episode of Daniel 4, where he was driven to eat grass like an ox until he acknowledged that God rules over the kingdoms of men.</p>"},
"nebuchadrezzar": {"term":"Nebuchadrezzar","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"nebuchadrezzar"},"key_refs":["Jeremiah 21:2","Jeremiah 43:10","Ezekiel 26:7"],"intro":"<p>Nebuchadrezzar is the more accurate transliteration of the Babylonian king's name (<em>Nabu-kudurri-usur</em>), used consistently in Jeremiah and Ezekiel and occasionally in Kings. The form \"Nebuchadnezzar,\" used in Daniel and most of Kings and Chronicles, is an alternate Hebrew spelling that substitutes <em>n</em> for <em>r</em> in the middle of the name. Both forms refer to the same person — Nebuchadnezzar II, the Babylonian king who destroyed Jerusalem in 586 B.C. The variation reflects the different scribal traditions that preserved the two books of Kings/Chronicles/Daniel on one hand and the prophets Jeremiah/Ezekiel on the other.</p>"},
"nebushasban": {"term":"Nebushasban","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"nebushasban","smith":"nebushasban"},"key_refs":["Jeremiah 39:13"],"intro":"<p>Nebushasban was a Babylonian official, identified as \"the chief eunuch\" (Hebrew <em>Rab-saris</em>), who was among the Babylonian commanders sent by Nebuchadnezzar to oversee the treatment of Jeremiah after Jerusalem fell in 586 B.C. (Jer. 39:13). He participated in retrieving Jeremiah from the court of the guard and handing him over to Gedaliah the governor. His title indicates he was a high-ranking palace official in the Babylonian administration.</p>"},
"nebuzaradan": {"term":"Nebuzaradan","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"nebuzaradan","smith":"nebuzaradan","isbe":"nebuzaradan"},"key_refs":["2 Kings 25:8","Jeremiah 39:9","Jeremiah 40:1","Jeremiah 52:12"],"intro":"<p>Nebuzaradan was the captain of the guard (Hebrew <em>Rab-Tabbahim</em>, \"chief of the executioners/slaughterers\") under Nebuchadnezzar II, who was responsible for the destruction of Jerusalem and the temple in 586 B.C. He burned the temple, the palace, and the great houses, and broke down the walls of Jerusalem (2 Kgs. 25:8–10). He carried the bulk of the surviving population into Babylonian exile while leaving behind some of the poorest to tend the land. By the king's specific command he treated Jeremiah with consideration, offering him the choice of going to Babylon or remaining in Judah, and released him into Gedaliah's care (Jer. 39:11–14; 40:1–6).</p>"},
"necho-ii": {"term":"Necho II","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"necho-ii"},"key_refs":["2 Kings 23:29","2 Chronicles 35:20","2 Kings 23:33","Jeremiah 46:2"],"intro":"<p>Necho II (also Neco or Pharaoh Necho) was an Egyptian pharaoh of the 26th dynasty (reigned c. 610–595 B.C.) who marched his army north along the coast of Palestine to support the Assyrian remnant against the Babylonians. When Josiah king of Judah attempted to intercept him at Megiddo, Necho warned him that his quarrel was not with Judah, but Josiah fought and was fatally wounded (2 Kgs. 23:29; 2 Chr. 35:20–24). After Megiddo, Necho deposed Josiah's successor Jehoahaz, imposed tribute, and placed Jehoiakim on the throne (2 Kgs. 23:33–35). He was decisively defeated by Nebuchadnezzar at the battle of Carchemish in 605 B.C., ending Egyptian aspirations in the Levant (Jer. 46:2).</p>"},
"neck": {"term":"Neck","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"neck","isbe":"neck"},"key_refs":["Deuteronomy 28:48","Isaiah 10:27","Joshua 10:24","Romans 16:4"],"intro":"<p>Neck in Scripture is used figuratively in several significant ways. Submission was symbolized by placing one's foot on an enemy's neck, as Joshua had the Israelite commanders do to the five Amorite kings (Josh. 10:24). Servitude and oppression are described as an iron yoke on the neck (Deut. 28:48). Prophetic freedom from oppression is the \"yoke... broken because of the anointing\" (Isa. 10:27). Putting one's neck at risk is the idiom used by Paul to commend Priscilla and Aquila, who \"risked their necks\" for his life (Rom. 16:4). The stiff neck — Hebrew <em>qesheh-oref</em> — became the standard biblical expression for stubborn resistance to God's commands (Ex. 32:9; Deut. 9:13; Acts 7:51).</p>"},
"necromancer": {"term":"Necromancer","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"necromancer"},"key_refs":["Deuteronomy 18:11","1 Samuel 28:7","Isaiah 8:19"],"intro":"<p>A necromancer (from Greek <em>nekros</em>, dead, and <em>manteia</em>, divination) was one who claimed to interrogate the spirits of the dead to discover the secrets of the future. The Mosaic law strictly prohibited necromancy as an abomination punishable by death (Deut. 18:10–11; Lev. 19:31; 20:27). The most celebrated biblical example is Saul's consultation of the medium at En-dor before the battle of Gilboa, where the figure of Samuel appeared and announced Saul's imminent death (1 Sam. 28:7–19). Isaiah mocked those who consult the dead on behalf of the living: \"Should not a people consult their God? Should they consult the dead on behalf of the living?\" (Isa. 8:19).</p>"},
"nedabiah": {"term":"Nedabiah","category":"people","hitchcock_meaning":"prince or vow of the Lord","source_ids":{"easton":"nedabiah","smith":"nedabiah","isbe":"nedabiah"},"key_refs":["1 Chronicles 3:18"],"intro":"<p>Nedabiah (meaning <em>moved by the LORD; the LORD is willing</em>) was a son of Jeconiah (Jehoiachin), the captive king of Judah who was carried to Babylon (1 Chr. 3:18). He thus belonged to the Davidic royal line during its exile but is otherwise unattested. His name appears only in the genealogical list of the royal family's continuation in captivity.</p>"},
"needle": {"term":"Needle","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"needle","isbe":"needle"},"key_refs":["Matthew 19:24","Mark 10:25","Luke 18:25"],"intro":"<p>Needle appears in one of Jesus' most striking pronouncements: \"It is easier for a camel to go through the eye of a needle than for a rich man to enter the kingdom of God\" (Matt. 19:24; Mark 10:25; Luke 18:25). Some interpreters have proposed that \"needle's eye\" referred to a small gate in Jerusalem's wall through which a loaded camel could barely squeeze, but this explanation has no early support and seems to soften the intentional hyperbole. The disciples understood the saying as depicting something humanly impossible, asking \"Who then can be saved?\" — to which Jesus replied, \"With men this is impossible, but with God all things are possible.\" The teaching addresses not the impossibility of wealthy people's salvation but the impossibility of self-salvation.</p>"},
"neginah": {"term":"Neginah","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"neginah","smith":"neginah"},"key_refs":["Psalms 61:1","Lamentations 3:14"],"intro":"<p>Neginah (singular; plural Neginoth) is a Hebrew musical term appearing in the title of Psalm 61 (\"on stringed instruments\") and in Lamentations 3:14, where the afflicted speaker becomes \"their song\" or \"their music.\" The word derives from a root meaning to play a stringed instrument. The related plural <em>Neginoth</em> appears in the titles of Psalms 4, 6, 54, 55, 67, and 76, indicating these psalms were to be performed with string accompaniment.</p>"},
"neginoth": {"term":"Neginoth","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"neginoth","smith":"neginoth"},"key_refs":["Psalms 4:1","Psalms 6:1","Psalms 54:1","Psalms 55:1"],"intro":"<p>Neginoth (Hebrew <em>neginot</em>, meaning \"stringed instruments\" or \"pluckings\") is a musical direction appearing in the titles of six psalms (Ps. 4, 6, 54, 55, 67, 76), indicating they were composed for performance on stringed instruments. The term derives from the root <em>nagan</em>, to play a stringed instrument. The singular form Neginah appears in Psalm 61:1 and Lamentations 3:14. The exact nature of the instruments intended — lyre, harp, lute — is uncertain, but the term consistently signals a string-instrument performance tradition within the temple liturgy.</p>"},
"nehelamite": {"term":"Nehelamite","category":"people","hitchcock_meaning":"dreamer; vale; brook","source_ids":{"easton":"nehelamite"},"key_refs":["Jeremiah 29:24","Jeremiah 29:31","Jeremiah 29:32"],"intro":"<p>Nehelamite is the designation of Shemaiah, a false prophet who sent unauthorized letters from Babylon to the priest Zephaniah in Jerusalem after Jeremiah's letter to the exiles (Jer. 29:24–32). Shemaiah urged the priests to rebuke and imprison Jeremiah for his letter counseling the exiles to settle in Babylon and seek its welfare. Jeremiah received a word from God pronouncing judgment on Shemaiah and his descendants: he would not live to see God's restoration of his people. The meaning of \"Nehelamite\" is uncertain — it may indicate his place of origin or family name.</p>"},
"nehemiah": {"term":"Nehemiah","category":"people","hitchcock_meaning":"consolation; repentance of the Lord","source_ids":{"easton":"nehemiah","smith":"nehemiah","isbe":"nehemiah"},"key_refs":["Nehemiah 1:1","Nehemiah 2:5","Nehemiah 6:15","Nehemiah 13:6"],"intro":"<p>Nehemiah (meaning <em>consoled by the LORD</em>), son of Hachaliah, was a Jewish cupbearer to the Persian king Artaxerxes I who received news of Jerusalem's broken walls and burned gates (Neh. 1:1–3). His prayer of confession and intercession (Neh. 1:5–11) was followed by his request to return and rebuild the city, which Artaxerxes granted in the 20th year of his reign (c. 445 B.C.). Against opposition from Sanballat and Tobiah and despite assassination plots, Nehemiah organized the Jews of Jerusalem and completed the rebuilding of the city walls in 52 days (Neh. 6:15). He served as governor of Judah for twelve years, during which he also worked with Ezra on covenant renewal and social reforms — enforcing Sabbath observance, dissolving mixed marriages, and ensuring the Levites' support (Neh. 13).</p>"},
"nehemiah-book-of": {"term":"Nehemiah, Book of","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"nehemiah-book-of","isbe":"nehemiah-book-of"},"key_refs":["Nehemiah 1:1","Nehemiah 8:1","Nehemiah 9:1","Nehemiah 13:31"],"intro":"<p>The Book of Nehemiah was originally part of a single work with Ezra in the Hebrew canon, together recounting the return from Babylonian exile and the restoration of Jerusalem. The book draws heavily on Nehemiah's personal memoirs (chs. 1–7; 12:27–47; 13), supplemented by lists, a prayer of confession (ch. 9), and the covenant renewal account (ch. 10). Its central narrative is the 52-day rebuilding of Jerusalem's walls under Nehemiah's leadership despite Samaritan opposition. The great assembly of Ezra 8–10 (Nehemiah's ch. 8–10 in most numbering), during which Ezra read the law and the people wept and renewed the covenant, represents the spiritual culmination of the restoration period. The book covers events from approximately 445 to 433 B.C.</p>"},
"nehiloth": {"term":"Nehiloth","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"nehiloth","smith":"nehiloth","isbe":"nehiloth"},"key_refs":["Psalms 5:1"],"intro":"<p>Nehiloth is a musical term in the title of Psalm 5 (\"upon Nehiloth\"), generally interpreted as referring to wind instruments — specifically flutes or pipes (from the root <em>halal</em>, to bore or pierce). Some scholars have proposed that it designates a wind instrument that was to accompany the psalm's performance, while others read it as a tune name. The LXX renders it as referring to \"inheritances,\" suggesting a different reading tradition. The exact meaning and the instrument intended remain uncertain.</p>"},
"nehushta": {"term":"Nehushta","category":"people","hitchcock_meaning":"made of brass","source_ids":{"easton":"nehushta","smith":"nehushta","isbe":"nehushta"},"key_refs":["2 Kings 24:8"],"intro":"<p>Nehushta (meaning <em>of brass</em>) was the daughter of Elnathan of Jerusalem and the queen mother under her son Jehoiachin (Jeconiah), king of Judah (2 Kgs. 24:8). She was carried into Babylonian captivity together with Jehoiachin in the first deportation of 597 B.C. (2 Kgs. 24:15). Jeremiah may allude to her in his lament over the exile of Jeconiah, addressing the king and his mother together (Jer. 22:26; 13:18). Her name's association with bronze may connect symbolically with the Nehushtan — the bronze serpent.</p>"},
"nehushtan": {"term":"Nehushtan","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"nehushtan","smith":"nehushtan","isbe":"nehushtan"},"key_refs":["Numbers 21:8","2 Kings 18:4","John 3:14"],"intro":"<p>Nehushtan (meaning <em>a thing of brass; the brazen thing</em>) was the name given to the bronze serpent that Moses had made in the wilderness when the Israelites were plagued by fiery serpents (Num. 21:8–9). Anyone bitten who looked at the bronze serpent lived. This object was preserved and eventually set up as an object of worship in Israel, where the people burned incense to it, calling it Nehushtan — perhaps contemptuously, as though dismissing it as \"mere brass.\" Hezekiah broke it in pieces as part of his religious reform (2 Kgs. 18:4). Jesus used the incident as a type of his own crucifixion: \"As Moses lifted up the serpent in the wilderness, even so must the Son of Man be lifted up, that whoever believes in him may have eternal life\" (John 3:14–15).</p>"},
"neiel": {"term":"Neiel","category":"places","hitchcock_meaning":"commotion, or moving, of God","source_ids":{"easton":"neiel","smith":"neiel","isbe":"neiel"},"key_refs":["Joshua 19:27"],"intro":"<p>Neiel was a town on the border of Asher, mentioned in Joshua 19:27 as one of the boundary markers of the tribal allotment. It is listed between Cabul and Sidon in the territory description. The site's precise identification is uncertain, with some scholars proposing Khirbet Ya'nin in the hills of lower Galilee.</p>"},
"nekeb": {"term":"Nekeb","category":"places","hitchcock_meaning":None,"source_ids":{"easton":"nekeb","smith":"nekeb","isbe":"nekeb"},"key_refs":["Joshua 19:33"],"intro":"<p>Nekeb was a town on the border of Naphtali, listed in Joshua 19:33 among the boundary points of the tribal allotment. It is typically identified with the modern site of Khirbet el-Waura or a nearby location in lower Galilee. Like several border towns in the Naphtali allotment it appears only in this single territorial reference.</p>"},
"nemuel": {"term":"Nemuel","category":"people","hitchcock_meaning":"the sleeping of God","source_ids":{"easton":"nemuel","smith":"nemuel","isbe":"nemuel"},"key_refs":["Numbers 26:9","1 Chronicles 4:24"],"intro":"<p>Nemuel is the name of two men. (1.) A son of Eliab and brother of Dathan and Abiram, who perished in the wilderness with Korah's rebellion (Num. 26:9). (2.) The firstborn son of Simeon, Jacob's second son, who is also called Jemuel in Genesis 46:10 and Exodus 6:15 (1 Chr. 4:24). He founded the family of the Nemuelites (Num. 26:12). The name variation between Nemuel and Jemuel likely reflects different textual traditions.</p>"},
"nephilim": {"term":"Nephilim","category":"concepts","hitchcock_meaning":None,"source_ids":{"easton":"nephilim","isbe":"nephilim"},"key_refs":["Genesis 6:4","Numbers 13:33"],"intro":"<p>Nephilim (Hebrew, variously translated \"giants\" or left untranslated) are mentioned in two passages: Genesis 6:4, where they appear on the earth \"when the sons of God came in to the daughters of man,\" and Numbers 13:33, where the Israelite spies report seeing the descendants of Anak who \"seemed to us like grasshoppers\" — and call them Nephilim. The identity and nature of the Nephilim is among the most debated questions in biblical interpretation. Some read \"sons of God\" as fallen angels, others as the Sethite righteous line or as kings claiming divine prerogative. The Septuagint and later tradition translated them as \"giants\" (<em>gigantes</em>). Whatever their nature, the passage in Genesis presents them as part of the context of human wickedness that prompted the flood.</p>"},
"nephtoah": {"term":"Nephtoah","category":"places","hitchcock_meaning":None,"source_ids":{"easton":"nephtoah","isbe":"nephtoah"},"key_refs":["Joshua 15:9","Joshua 18:15"],"intro":"<p>Nephtoah (or the \"waters of Nephtoah\") was a spring on the border between Judah and Benjamin, appearing in both tribal boundary descriptions (Josh. 15:9; 18:15). It is identified with Lifta, a village about two miles northwest of Jerusalem, where a strong spring rises near the border of the two territories. The site marks an important watershed and tribal boundary point.</p>"},
"ner": {"term":"Ner","category":"people","hitchcock_meaning":"a lamp; new-tilled land","source_ids":{"easton":"ner","smith":"ner","isbe":"ner"},"key_refs":["1 Samuel 14:50","1 Chronicles 8:33","1 Chronicles 9:36"],"intro":"<p>Ner (meaning <em>lamp</em>) was the grandfather of King Saul and father of Abner, the commander of Saul's army (1 Sam. 14:50–51; 1 Chr. 8:33). He was a Benjaminite, son of Jehiel the founder of Gibeon. The genealogical relationship between Ner, Kish, and Saul is given in slightly different forms in 1 Samuel 14:51 and 1 Chronicles 8:33; the most natural reading makes Ner the uncle of Kish (Saul's father), thus making Ner the great-uncle of Saul and Abner Saul's first cousin. His name connects to the biblical motif of the lamp as God's provision and guidance.</p>"},
"nereus": {"term":"Nereus","category":"people","hitchcock_meaning":"same as Ner","source_ids":{"easton":"nereus","smith":"nereus","isbe":"nereus"},"key_refs":["Romans 16:15"],"intro":"<p>Nereus was a Roman Christian greeted by Paul at the close of Romans (Rom. 16:15), along with his sister and Olympas and those with them. His name was common in the Roman world, being that of a sea-god in Greek mythology. Some scholars have identified him with a Nereus mentioned in the Acts of Nereus and Achilleus, an apocryphal text, who is said to have been a member of the household of Flavia Domitilla. If so, he had connections to the Roman aristocracy. Beyond this greeting nothing is known of him.</p>"},
"nergal": {"term":"Nergal","category":"concepts","hitchcock_meaning":"the great man; the hero","source_ids":{"easton":"nergal","smith":"nergal","isbe":"nergal"},"key_refs":["2 Kings 17:30"],"intro":"<p>Nergal was the Assyrian and Babylonian god of war, pestilence, and the underworld, associated with the planet Mars and regarded as a god of destruction and death. He is mentioned in 2 Kings 17:30 as one of the foreign deities worshipped by the Cuthean settlers whom Sargon II resettled in Samaria after the deportation of the northern tribes: \"the men of Cuth made Nergal.\" His cult center was at Cutha (modern Tell Ibrahim northeast of Babylon), and he is frequently invoked in Assyrian royal inscriptions and curses. His name appears in the compound name Nergal-Sharezer (Jer. 39:3, 13).</p>"},
"nergal-sharezer": {"term":"Nergal-Sharezer","category":"people","hitchcock_meaning":"treasurer of Nergal","source_ids":{"easton":"nergal-sharezer","isbe":"nergal-sharezer"},"key_refs":["Jeremiah 39:3","Jeremiah 39:13"],"intro":"<p>Nergal-Sharezer was a Babylonian official present at the fall of Jerusalem in 586 B.C., named among the princes of Nebuchadnezzar who sat in the Middle Gate of Jerusalem after the city was breached (Jer. 39:3, 13). His title Rab-mag indicates a high court or military office. He has been identified by some scholars with Neriglissar, the Babylonian king who succeeded Nebuchadnezzar's son Evil-Merodach and whose name in cuneiform is Nergal-shar-usur. If the identification is correct, he was Nebuchadnezzar's son-in-law and present at the siege in an official capacity.</p>"},
"nero": {"term":"Nero","category":"people","hitchcock_meaning":None,"source_ids":{"easton":"nero","isbe":"nero"},"key_refs":["Acts 25:11","Philippians 4:22","2 Timothy 4:17"],"intro":"<p>Nero Claudius Caesar Augustus Germanicus (reigned 54–68 A.D.) was the Roman emperor before whom Paul appealed his case as a Roman citizen (Acts 25:11). Though not named in the canonical New Testament, Nero's reign provides the context for several epistles: Paul's reference to the \"household of Caesar\" (Phil. 4:22) and his confidence that the Lord had delivered him \"from the lion's mouth\" (2 Tim. 4:17) are often read as allusions to the imperial court and threat of execution under Nero. In 64 A.D. Nero blamed Christians for the great fire of Rome and initiated the first imperial persecution of the church, during which both Peter and Paul are traditionally said to have been martyred. Nero committed suicide in 68 A.D. following a military revolt. The number 666 in Revelation 13:18 has been interpreted by many scholars as a Hebrew gematria for \"Nero Caesar.\"</p>"},
}

wrote = skipped = 0
